import React from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import '../../styles/Courses.css';
import { 
  FaPlayCircle, 
  FaClock, 
  FaUserGraduate, 
  FaStar,
  FaBookmark,
  FaShareAlt
} from 'react-icons/fa';

const CourseCard = ({ course, isEnrolled }) => {
  const { currentUser } = useAuth();

  const { enrollCourse } = useAuth();

  const handleEnroll = async () => {
    if (!currentUser) {
      // redirect to login if not authenticated
      window.location.href = '/login';
      return;
    }
    const res = enrollCourse(course.id);
    if (res.success) {
      // simple feedback
      alert(res.enrolled ? `Enrolled in ${course.title}` : `Unenrolled from ${course.title}`);
    }
  };

  const handleShare = async () => {
    const shareUrl = window.location.origin + `/learn/${course.id}`;
    if (navigator.share) {
      try { await navigator.share({ title: course.title, url: shareUrl }); }
      catch (e) { /* ignore */ }
    } else {
      try {
        await navigator.clipboard.writeText(shareUrl);
        alert('Course link copied to clipboard');
      } catch (e) {
        prompt('Copy this link', shareUrl);
      }
    }
  };

  return (
    <div className="course-card">
      <div className="course-image">
        <img src={course.image} alt={course.title} />
        <div className="course-category">{course.category}</div>
        <button className="bookmark-btn">
          <FaBookmark />
        </button>
      </div>

      <div className="course-content">
        <div className="course-header">
          <h3>{course.title}</h3>
          <div className="course-rating">
            <FaStar />
            <span>4.8</span>
          </div>
        </div>

        <p className="course-description">{course.description}</p>

        <div className="course-meta">
          <div className="meta-item">
            <FaClock />
            <span>{course.duration}</span>
          </div>
          <div className="meta-item">
            <FaUserGraduate />
            <span>{course.level}</span>
          </div>
        </div>

        <div className="course-footer">
          {isEnrolled ? (
            <Link to={`/learn/${course.id}`} className="btn btn-primary">
              <FaPlayCircle /> Continue Learning
            </Link>
          ) : (
            <button onClick={handleEnroll} className="btn btn-enroll">
              Enroll Now
            </button>
          )}
          
          <button className="btn btn-outline">
            <FaShareAlt /> Share
          </button>
        </div>

        <div className="progress-container">
          <div className="progress-bar">
            <div className="progress" style={{ width: '65%' }}></div>
          </div>
          <span className="progress-text">65% Complete</span>
        </div>
      </div>
    </div>
  );
};

export default CourseCard;
